INSERT INTO levels (k,code,qd,name,cls,trigger_desc,action_desc,auth_desc,eoc,hk) VALUES (0,'XANH','Cấp 0 – Sẵn sàng','SẴN SÀNG MÙA MƯA BÃO','lv0','Mùa mưa bão, chưa có cảnh báo cụ thể (Điều 20.1 QĐ.03).','Kiểm tra định kỳ · kho đủ định mức (hàng hỏng/hết hạn KHÔNG tính vào định mức) · danh sách trực + đầu mối sẵn sàng · bản tin Zalo 06:30/16:30 · diễn tập, hợp đồng nguồn cung.','Đơn vị / cơ sở tự duy trì','EOC Level 3 – Giám sát','≈ Tín hiệu T1 (HK)');
INSERT INTO levels (k,code,qd,name,cls,trigger_desc,action_desc,auth_desc,eoc,hk) VALUES (1,'VÀNG','Cấp 1 – Cảnh giác','CẢNH GIÁC (≈72 GIỜ)','lv1','Dự báo bão/mưa lớn khả năng ảnh hưởng trong ~72 giờ hoặc dấu hiệu bất thường tại cơ sở · dông lốc · gió giật cấp 6–7 (39–61 km/h).','Họp nhanh đầu mối cơ sở; kiểm kê + chạy thử bơm, máy phát, bộ đàm, đèn; vệ sinh thoát nước; chụp hiện trạng; kích hoạt kịch bản MƯA khi có mưa; dừng làm việc trên cao khi gió giật mạnh.','TGĐ/người ủy quyền · GĐ đơn vị/BQL/CHT được kích hoạt tại chỗ + báo cáo ngay','EOC Level 3→2','≈ Tín hiệu T3 (HK)');
INSERT INTO levels (k,code,qd,name,cls,trigger_desc,action_desc,auth_desc,eoc,hk) VALUES (2,'CAM','Cấp 2 – Chuẩn bị ứng phó','CHUẨN BỊ ỨNG PHÓ (24–48H)','lv2','Nguy cơ ảnh hưởng trong 24–48 giờ · TIN BÃO KHẨN CẤP · mưa lớn kéo dài, thoát nước quá tải · cảnh báo cao của cơ quan thẩm quyền · RRTT cấp 3.','Đưa thiết bị ra vị trí + sạc đầy; gia cố – chằng buộc; bảo vệ tủ điện/phòng máy chủ + sao lưu dữ liệu; chốt trực 24/24; mua gối đầu nhóm 2; mở mã chi phí; chốt giờ dừng thi công; sẵn sàng mở kho ≤15 phút.','TGĐ/người được ủy quyền quyết định · báo cáo Chủ tịch','EOC Level 2 – Một phần','≈ Tín hiệu T8 (HK)');
INSERT INTO levels (k,code,qd,name,cls,trigger_desc,action_desc,auth_desc,eoc,hk) VALUES (3,'ĐỎ','Cấp 3 – Khẩn cấp','KHẨN CẤP','lv3','Bão/mưa ảnh hưởng TRỰC TIẾP · ngập, mất điện, hư hỏng kết cấu, sự cố kỹ thuật · nguy cơ đe dọa người và tài sản · gió ≥cấp 10.','DỪNG hoạt động – sơ tán – lập vùng cấm; trực 24/24; điều chuyển kho theo lệnh BCH; phối hợp cơ quan chuyên trách 112/114/115; chỉ hoạt động lại khi xác nhận an toàn theo Điều 52.','CHỦ TỊCH quyết định · chỉ huy hiện trường được xử lý tức thời khi đe dọa tính mạng','EOC Level 1 – Toàn phần','≈ Tín hiệu T10 (HK)');
INSERT INTO levels (k,code,qd,name,cls,trigger_desc,action_desc,auth_desc,eoc,hk) VALUES (4,'ĐẶC BIỆT','Cấp 4 – Đặc biệt','HUY ĐỘNG TOÀN GROUP','lv4','Thiệt hại lớn · NHIỀU cơ sở cùng bị ảnh hưởng · khu vực bị chia cắt · cần huy động toàn Group hoặc phối hợp cơ quan nhà nước (Điều 20.5).','Chủ tịch trực tiếp chỉ huy; phương án đặc biệt; điều chuyển lực lượng – kho giữa các cơ sở; kích hoạt CỨU TRỢ THIÊN TAI (Chương VII); báo cáo liên tục; phối hợp chính quyền/MTTQ/Chữ thập đỏ.','CHỦ TỊCH trực tiếp chỉ huy và phê duyệt phương án riêng','EOC Level 1 + liên cơ quan','Vượt T10 – ứng phó thảm họa');
