INSERT INTO task_templates (id,code,unit_code,phase_id,min_level,title,suggested_owner,suggested_checker,note) VALUES ('e248cc23-dd2b-4f0b-b8fa-d16955620252','TT-0208','MKT','DUR',4,'CẤP 4: Phát ngôn một đầu mối được phân công; kiểm duyệt hình ảnh nhạy cảm; không công bố dữ liệu cá nhân (Điều 66)','Truyền thông + MKT Lead','VP Chủ tịch',NULL);
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-B1','B',1,'Mưa lớn cục bộ 50–120mm / dông sét','Cảnh báo mưa dông của NCHMF; mây dông phát triển nhanh trong 3–6h.','Ngập cục bộ điểm trũng công trường 20–40cm; nước tràn hố PIT; sét đánh khu vực cẩu tháp; 1 máy bơm quá tải.','Đội cơ điện CT + tổ Kỹ thuật các BQL; trực bơm 2 người/vị trí.','Bơm vận hành ≤10 phút từ khi nước dâng; báo cáo mực nước mỗi giờ; 0 tai nạn điện.','Mỗi tháng 1 lần đầu mùa (tháng 5–6).');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-B2','B',2,'ATNĐ / Bão cấp 8–9 vào Bắc Bộ (RRTT cấp 3)','Tin bão KHẨN CẤP – dự kiến ảnh hưởng đất liền ≤48h; gió Bắc Ninh cấp 6–8, giật 9–10.','Tốc mái tôn nhà tạm, đổ 5–10% cây xanh, bung 1–2 cửa kính căn hộ chưa chèn chốt, mất điện lưới 2–6h từng khu.','Toàn bộ gói TRƯỚC BÃO T-48→T-6; trực 24/24 tại 5 BQL + công trường; BCH họp 2 lần/ngày.','100% nhiệm vụ trước bão hoàn thành trước T-6; 100% nhân sự xác nhận nhận lệnh ≤30 phút.','Diễn tập bàn tròn (tabletop) tháng 5 hằng năm.');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-B3','B',3,'Bão mạnh cấp 10–12 ảnh hưởng trực tiếp (kịch bản Yagi)','Tin bão khẩn cấp/trên đất liền; tâm bão qua đồng bằng Bắc Bộ; gió BN cấp 9–11 giật 12–14; RRTT cấp 3–4.','Theo bài học Yagi 9/2024: vỡ kính mặt dựng & căn hộ hàng loạt tại nhà cao tầng; nước tràn qua khe cửa; đổ >30% cây; tốc mái kho; mất điện diện rộng 12–48h; sập giàn giáo nếu chưa gia cố; nguy cơ ngập hầm do mưa hoàn lưu sau bão.','Cấp ĐỎ toàn tập đoàn; chỉ lực lượng trực ở lại; BCH trực 24/24 tại phòng điều hành.','0 thương vong; thời gian khôi phục vận hành tòa nhà ≤72h; công trường thi công lại ≤7 ngày.','Diễn tập thực binh 1 lần/năm trước mùa bão (tháng 6) — bắt buộc theo Luật PCCC&CNCH cho phần CNCH.');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-B4','B',3,'Ngập hầm xe do mưa hoàn lưu (sự cố trọng điểm)','Mưa hoàn lưu sau bão >150mm/12h; nước đường đô thị dâng tràn ram dốc; bơm hầm quá công suất hoặc mất điện.','Nước vào hầm B1 200–500m³; nguy cơ ngập tủ điện, trạm bơm PCCC đặt tại hầm; ~50–200 xe máy + ô tô trong hầm; nguy cơ chập điện – cháy (liên động PCCC).','Tổ kỹ thuật + bảo vệ dự án bị ảnh hưởng; chi viện bơm từ dự án lân cận + công trường (bơm 5HP); xe cơ động VP.','Phát hiện nước tràn ≤5 phút (tuần tra 30 phút/lần); di dời xe điện ≤60 phút; 0 sự cố điện giật.','Diễn tập kéo bơm chi viện liên dự án 2 lần/mùa.');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-B5','B',2,'Bung – vỡ kính mặt ngoài khi gió giật','Gió giật ≥cấp 9 tại chỗ; phát hiện cửa kính rung mạnh/bung nẹp tại căn hộ, sảnh, siêu thị hoặc vách kính VP tầng 3-4 CTN.','1–5 ô kính vỡ rơi từ tầng cao; nước hắt vào căn hộ/khu hoàn thiện; nguy hiểm người bên dưới.','Tổ bảo trì + bảo vệ tại chỗ; đội nhôm kính công trường chi viện sau gió.','Rào chắn ≤10 phút từ khi phát hiện; 0 người bị thương do kính rơi.','Đưa vào diễn tập bàn tròn cùng KB-B2.');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-B6','B',4,'Mất điện lưới toàn khu >24h · nhiều cơ sở cùng ảnh hưởng','Lưới điện khu vực sự cố diện rộng (kịch bản Yagi: nhiều nơi mất điện 2–5 ngày).','5 tòa nhà chạy máy phát; nhiên liệu tiêu hao ~40–60 lít/máy/ngày; thang máy dừng; nước sinh hoạt phụ thuộc bơm.','Tổ kỹ thuật các BQL + Mua hàng (tiếp dầu) + MKT (thông báo cắt giảm tải).','Không gián đoạn bơm PCCC; cư dân có nước sinh hoạt ≥2 khung giờ/ngày; dầu dự trữ không xuống dưới 30%.','Chạy thử tải thật máy phát 1 lần/quý.');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-C1','C',2,'Cháy căn hộ (sự cố mức 1–2)','Báo cháy tự động 1 điểm hoặc cư dân báo qua hotline; khói từ 1 căn hộ.','Cháy chập điện/bếp trong 1 căn; khói lan hành lang 1 tầng; 5–20 cư dân cần hướng dẫn thoát nạn tầng đó.','Đội PCCC cơ sở BQL (ca trực 7–8 người); cảnh sát PCCC 114.','114 được gọi ≤2 phút; đội cơ sở tiếp cận ≤4 phút; sơ tán tầng ≤10 phút.','Diễn tập từng tòa ≥1 lần/năm cùng cư dân (mô hình Mori Building – có cả cư dân tham gia).');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-C2','C',3,'Cháy hầm xe – xe điện (rủi ro cao nhất NƠXH)','Báo khói tầng hầm; camera phát hiện khói khu sạc xe điện.','1 xe máy điện cháy khi sạc, lan 3–10 xe liền kề; khói độc đặc hầm rất nhanh; nguy cơ nổ pin lithium tái phát nhiều giờ.','Toàn đội PCCC cơ sở + 114 (báo rõ «cháy xe điện tầng hầm»); cắt điện toàn hầm.','Phát hiện ≤3 phút (tuần tra + camera); báo động toàn tòa ≤5 phút; 0 người kẹt trong hầm.','Diễn tập chuyên đề hầm xe 1 lần/năm; kiểm tra khu sạc hằng tuần theo Luật 55/2024.');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-C3','C',3,'Chập điện do ngập → cháy (liên động PCLB-PCCC)','Đang mưa bão/ngập hầm, phát hiện khét – khói tại tủ điện, phòng kỹ thuật.','Tủ điện tầng hầm ẩm nước phóng điện; hệ báo cháy có thể lỗi do ẩm; lực lượng đang phân tán chống ngập.','Tổ kỹ thuật (ưu tiên số 1 quay về sự cố điện) + đội PCCC cơ sở; 114 nếu vượt khả năng.','Cắt điện đúng khu vực ≤3 phút; 0 điện giật; bơm chống ngập không gián đoạn >15 phút.','Ghép vào diễn tập PCLB thường niên (bắt buộc có tình huống này).');
INSERT INTO scenarios (id,grp,lv,name,trigger_desc,assumption,force_desc,sla,drill) VALUES ('KB-C4','C',2,'Cháy tại công trường (hàn cắt / kho vật tư / lán trại)','Phát hiện khói-lửa tại tầng thi công, kho vật tư, khu lán trại nhà thầu.','Vảy hàn bén bạt/xốp/ván khuôn; đám cháy phát triển nhanh theo vật liệu; công nhân đông, lối thoát công trường phức tạp.','Đội PCCC cơ sở công trường (≥25 người theo Luật 55/2024) + bảo vệ + 114.','Báo động ≤2 phút; điểm danh đủ quân số ≤15 phút; phiếu công tác nóng 100% khi hàn cắt.','Diễn tập công trường 1 lần/năm + huấn luyện ATLĐ đầu vào 100% công nhân.');
