INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B3',3,'Cấm tuyệt đối ra ngoài xử lý khi gió mạnh (bài học tử vong Yagi)');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B3',4,'Máy phát chỉ cấp tải ưu tiên; theo dõi hầm bằng phao báo mức');
