INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B4',2,'Di dời xe (ưu tiên xe điện) lên mặt đất theo loa gọi từng tầng');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B4',3,'CẮT ĐIỆN hầm trước khi nước chạm tủ; giữ nguồn riêng cho bơm');
