INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B5',1,'Rào chắn ngay khu vực bên dưới, sơ tán người khỏi vệt rơi');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B5',2,'Đưa cư dân/căn hộ liên quan sang phòng SHCĐ tầng an toàn');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B5',3,'KHÔNG cử người ra gia cố khi gió còn mạnh — chỉ xử lý từ phía trong');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B5',4,'Chèn khăn/băng keo chữ X các ô kính lớn liền kề');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B5',5,'Sau gió: đội nhôm kính vá tạm bằng bạt + ván, lập biên bản thiệt hại');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B6',1,'Máy phát chỉ cấp tải ưu tiên: bơm nước SH theo khung giờ, bơm PCCC, chiếu sáng hành lang, 1 thang máy cứu hộ');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B6',2,'Lập lịch bơm nước + thông báo khung giờ cho cư dân');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B6',3,'Điều phối tiếp dầu: định mức 200 lít/dự án, đặt thêm theo hợp đồng nguyên tắc');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B6',4,'Điểm sạc điện thoại miễn phí tại sảnh (bài học Viettel sau Yagi)');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-B6',5,'Theo dõi nhiệt độ máy phát, nghỉ luân phiên theo khuyến cáo kỹ thuật');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C1',1,'Bấm chuông báo động tầng + GỌI 114 ngay (không chờ xác minh xong)');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C1',2,'Cắt điện tầng cháy; thang máy về tầng 1 khóa');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C1',3,'Đội cơ sở dùng bình + họng nước khống chế; cứu người trước');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C1',4,'Hướng dẫn cư dân thoát theo thang bộ, khăn ướt che mũi, KHÔNG thang máy');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C1',5,'Đón xe 114, bàn giao sơ đồ + chìa khóa kỹ thuật; bảo vệ hiện trường');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C2',1,'Báo động toàn tòa + gọi 114 nêu rõ cháy pin xe điện');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C2',2,'Kích hoạt quạt hút khói hầm; cắt điện hầm & trạm sạc');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C2',3,'TUYỆT ĐỐI không dùng nước trực tiếp vào pin đang cháy gần người — dùng bình chuyên dụng/cát, ưu tiên cô lập & sơ tán');
