INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C2',5,'Sau dập: canh chừng tái cháy pin ≥24h, kiểm định trước khi mở hầm');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C3',1,'CẮT ĐIỆN tổng khu vực sự cố trước — người cắt phải đứng nơi khô, có ủng + găng cách điện');
