INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C4',1,'Còi báo động toàn công trường + gọi 114');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C4',2,'Cắt điện khu vực; di chuyển bình khí, sơn, dung môi ra xa');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C4',3,'Dập bằng bình bột + cát; nước chỉ khi không còn điện');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C4',4,'Điểm danh toàn bộ công nhân theo tổ đội tại điểm tập kết');
INSERT INTO scenario_actions (scenario_id,seq,action_text) VALUES ('KB-C4',5,'Điều tra nguyên nhân, siết phiếu công tác nóng (hot-work permit)');
