INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('A. Bảo hộ cá nhân','Mũ bảo hộ cứu nạn có kính che','Cái',5,7,8,5,'Chống va đập vật rơi khi dọn cây, cứu nạn');
INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('A. Bảo hộ cá nhân','Ủng cao su mũi thép','Đôi',5,7,8,5,'Chống chập điện nước ngập hầm, chống đinh');
