INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('B. Phá dỡ cứu nạn','Rìu cứu hỏa chuyên dụng','Cái',1,4,4,2,'Gắn với tủ PCCC tòa nhà, không phụ thuộc ca trực');
INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('B. Phá dỡ cứu nạn','Búa tạ 5kg','Cái',1,4,4,2,'');
