INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('B. Phá dỡ cứu nạn','Kìm cộng lực cắt thép','Cái',1,4,4,2,'');
INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('C. Chống lụt – chống úng','Bơm tõm chìm chống úng','Cái',2,8,10,2,'Thống Nhất cao hơn do 2 hầm 4 dốc riêng biệt');
