INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('D. Thông tin – chiếu sáng','Đèn LED tích điện di động','Cái',3,16,16,6,'Cố định tại chốt trực, soi đường khi mất điện');
