INSERT INTO norms (category,name,unit,tn,cty,eco,ctn,note) VALUES ('D. Thông tin – chiếu sáng','Máy bộ đàm + dock sạc','Bộ',5,7,8,8,'Đủ quân số 1 ca; hết ca ký bàn giao cho ca sau');
INSERT INTO pccc_inventory (name,unit,tn,cty,eco,ctn,note,alert) VALUES ('Mặt nạ phòng độc','Cái',80,30,'—','—','TN: toàn bộ HẾT HSD → mua mới; ECO: rà HSD phin lọc hằng tháng',1);
