INSERT INTO cost_struct (code,name,description,evidence,approver) VALUES ('01','Nhân công trực & tăng cường','Lương trực bão theo ca 12h; làm thêm theo Bộ luật Lao động (150–300%); công nhật khắc phục','Bảng chấm công tách riêng giờ sự kiện + DS trực đã duyệt','Trưởng đơn vị chấm → KTT soát');
INSERT INTO cost_struct (code,name,description,evidence,approver) VALUES ('02','Nhu yếu phẩm & hậu cần trực','Định mức 4 bữa/người/ngày: 2 mì + 2 sữa + 2 bánh mì + 1 xúc xích + nước bình (phân bổ 20-20-15-10-20)','Máy tính hậu cần của hệ thống này; mua theo hợp đồng nguyên tắc','≤5tr: Trưởng BQL · >5tr: GĐ QLN');
INSERT INTO cost_struct (code,name,description,evidence,approver) VALUES ('03','Nhiên liệu máy phát – máy bơm','Dầu diesel 200 lít/dự án/đợt (định mức KHPCLB); xăng máy bơm 6.5HP','Nhật ký giờ chạy máy (máy nào, mục đích, số giờ) — chuẩn ICS','GĐ QLN duyệt vượt định mức');
INSERT INTO cost_struct (code,name,description,evidence,approver) VALUES ('04','Vật tư tiêu hao PCLB','Bao cát, bạt, dây thép, pin, cồn khô, thuốc y tế — theo định mức V7 & kho cứu trợ','Phiếu xuất kho + biên bản sử dụng; kiểm kê bù ngay sau sự kiện','Theo định mức: tự động · vượt: GĐ');
INSERT INTO cost_struct (code,name,description,evidence,approver) VALUES ('05','Thuê ngoài khẩn cấp','Bơm công suất lớn, cẩu kéo, nạo vét, xe tải — kích hoạt hợp đồng nguyên tắc ký trước mùa bão','CẤM cost-plus-%; đơn giá chốt trước hoặc theo giờ máy có nhật trình','GĐ ≤20tr · TGĐ >20tr');
INSERT INTO cost_struct (code,name,description,evidence,approver) VALUES ('06','Khắc phục – sửa chữa sau bão','Kính, mái, cửa, chống thấm, cây xanh, thiết bị hỏng','Biên bản thiệt hại + ảnh trước/sau + 3 báo giá (sau khi hết lệnh khẩn)','TGĐ duyệt theo tổng dự toán');
INSERT INTO cost_struct (code,name,description,evidence,approver) VALUES ('07','Cứu trợ & phúc lợi','Hỗ trợ CBNV/cư dân bị thiệt hại; xuất kho cứu trợ; điểm sạc miễn phí','Danh sách ký nhận + duyệt của BCH','TGĐ / Công đoàn');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Ban Chỉ huy (Chỉ huy trưởng: CHỦ TỊCH)','Quyết định cấp độ, điều phối, dừng/khôi phục hoạt động','Phê duyệt ngân sách, cứu trợ lớn');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Văn phòng Chủ tịch','Cơ quan THƯỜNG TRỰC: tiếp nhận tin, tham mưu cấp độ, phát lệnh, điều phối, liên hệ địa phương; phụ trách CNCH & thiện nguyện','Lệnh kích hoạt & báo cáo hợp nhất');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Trung tâm HC-NS','Quản lý TOÀN BỘ hệ thống kho (tổng, vệ tinh, tủ trực, cơ động, kho ảo), nhân sự, phương tiện, hậu cần, mua sắm; PCLB văn phòng','Sổ tổng nhập-xuất-tồn & quyền điều chuyển');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Cty TNHH Xây lắp Cát Tường','Phụ trách PCLB tại CÔNG TRƯỜNG: phương án theo cụm/tòa, thiết bị nâng, lực lượng trực kỹ thuật','Xác nhận điều kiện thi công lại');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Cty TNHH QLN TNT','Phụ trách PCLB các DỰ ÁN vận hành: trực 24/24, hầm, cư dân, kho vệ tinh','Bảo quản trực tiếp kho vệ tinh');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Trung tâm Pháp chế','Soạn thảo/rà soát Quy định, phương án, hợp đồng, hồ sơ cứu trợ; tư vấn trách nhiệm pháp lý, bồi thường','Hồ sơ sự cố nghiêm trọng');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Tài chính – Kế toán','Nguồn tiền, hạn mức tạm ứng, thanh toán khẩn; mã chi phí riêng từng đợt; không trộn nguồn đóng góp','Theo dõi riêng từng sự kiện/đợt cứu trợ');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('IT / Chuyển đổi số','Dữ liệu, UPS, cảm biến rò nước, cảnh báo, bộ đàm, kết nối, làm việc từ xa; phát triển app/AI hỗ trợ','Sao lưu & thứ tự khôi phục');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Truyền thông','Thông tin chính thức, cảnh báo, hướng dẫn; chỉ người được phân công phát ngôn','Kiểm duyệt hình ảnh & dữ liệu');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Kiểm soát nội bộ','Kiểm tra chéo số liệu, chứng từ, báo cáo, điểm bất thường về tài sản – chi phí','Báo cáo độc lập lên Ban Lãnh đạo');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('An toàn – Y tế & Bảo vệ','Nguy cơ, sơ cứu, thuốc, PPE, sức khỏe người tham gia; kiểm soát ra vào, chìa khóa dự phòng, tuần tra, camera, vùng cấm','Bàn giao ca & bảo vệ hiện trường');
INSERT INTO resp_matrix (role_title,responsibility,output_desc) VALUES ('Nhà thầu & người lao động','Chấp hành lệnh; thu dọn, che chắn, chằng buộc phạm vi của mình; báo nguy cơ ngay','Ký xác nhận & chịu trách nhiệm phạm vi');
INSERT INTO kho_model (tier,manager,content) VALUES ('1. Kho TỔNG (Group)','Trung tâm HC-NS quản lý trực tiếp','Thiết bị chiến lược, hàng giá trị cao, BỘ CƠ ĐỘNG (xuất ≤30 phút), hàng cứu trợ dùng chung, dự phòng điều chuyển');
INSERT INTO kho_model (tier,manager,content) VALUES ('2. Kho VỆ TINH','BQL/đơn vị sở tại bảo quản theo biên bản','Đủ xử lý giai đoạn ban đầu; gần khu rủi ro nhưng KHÔNG trong vùng ngập/cháy/sập; mở kho ≤15 phút');
INSERT INTO kho_model (tier,manager,content) VALUES ('3. TỦ/ĐIỂM TRỰC','Ca trực — bàn giao theo ca','Đồ lấy trong vài phút: bộ đàm, đèn, áo mưa, ủng, dây cứu hộ, túi sơ cứu');
INSERT INTO kho_model (tier,manager,content) VALUES ('4. Kho CƠ ĐỘNG','Theo lệnh ứng phó','Bộ hàng đóng gói sẵn/điểm tập kết tạm — phải có người quản lý, sổ nhanh, che chắn');
INSERT INTO kho_model (tier,manager,content) VALUES ('5. KHO ẢO (nguồn cung dự phòng)','HC-NS duy trì ≥2 NCC/nhóm trọng yếu','Hợp đồng nguyên tắc, đầu mối 24/7, giao 6h/12h/24h — là lớp bảo đảm, KHÔNG thay thế định mức tại hiện trường');
