INSERT INTO relief_levels (name,condition_desc,sla,authority) VALUES ('Cấp 1 – Hỗ trợ nhanh','< 50 hộ · giao thông bình thường','Sẵn sàng trong 24 giờ','Tổng Giám đốc / người được ủy quyền');
INSERT INTO relief_levels (name,condition_desc,sla,authority) VALUES ('Cấp 2 – Cứu trợ tập trung','50 – 300 hộ · có điểm tập kết','Sẵn sàng trong 18 giờ','Tổng Giám đốc / Chủ tịch');
INSERT INTO relief_levels (name,condition_desc,sla,authority) VALUES ('Cấp 3 – Cứu trợ khẩn cấp','> 300 hộ hoặc thiệt hại lớn','Sẵn sàng trong 12 giờ','Chủ tịch phê duyệt');
INSERT INTO relief_levels (name,condition_desc,sla,authority) VALUES ('Cấp 4 – Đặc biệt','Nhiều địa bàn · chia cắt · kéo dài nhiều ngày','Phương án riêng','CHỦ TỊCH trực tiếp chỉ huy');
INSERT INTO bench (org,practice,lesson) VALUES ('EVN / EVNNPC','Kích hoạt theo chuỗi công điện; BCH PCTT&TKCN các cấp; 4 tại chỗ; ứng trực 24/24; khôi phục nhanh sau bão','Cấp độ XANH→ĐỎ của CTG vận hành như «công điện nội bộ»: 1 lệnh kích hoạt = cả bộ máy chạy');
INSERT INTO bench (org,practice,lesson) VALUES ('Viettel (bão Yagi)','Cảnh báo 32 triệu thuê bao; 284 máy phát dự phòng; ~500 đội ứng cứu; 200 điểm sạc miễn phí; roaming chéo','Kịch bản KB-B6 mất điện >24h + điểm sạc sảnh cho cư dân');
INSERT INTO bench (org,practice,lesson) VALUES ('Vinhomes / Ocean City (Yagi)','Kích hoạt toàn đội kỹ thuật-môi trường ngay khi bão tan; cam kết diễn tập định kỳ; truyền thông trấn an','Gói R0–R7 sau bão + chuỗi content MKT-ZL-24→33');
INSERT INTO bench (org,practice,lesson) VALUES ('Tín hiệu bão Hồng Kông T1/T3/T8/T10','Mỗi nấc tín hiệu gắn sẵn checklist toàn xã hội; doanh nghiệp (cảng HIT) dừng/khôi phục theo trình tự ngược định sẵn','4 cấp XANH/VÀNG/CAM/ĐỎ ↔ gói nhiệm vụ gắn sẵn từng người trong file này');
INSERT INTO bench (org,practice,lesson) VALUES ('FEMA ICS/EOC (Mỹ)','3 cấp kích hoạt EOC; 5 khối chức năng; Finance/Admin mở mã chi phí ngay giờ đầu; hạn mức ủy quyền; cấm cost-plus-%','Ma trận cấp độ + module Chi phí chuẩn + mã sự kiện PCLB-năm-tên bão');
INSERT INTO bench (org,practice,lesson) VALUES ('Mitsubishi Estate (Nhật)','BCP điện dự phòng 72h; thỏa thuận trước với nhà thầu sửa chữa; đánh giá thiệt hại nhanh; PDCA sau diễn tập','Lộ trình GĐ3: chuẩn 72h + hợp đồng nguyên tắc NCC + AAR 4 câu hỏi');
INSERT INTO bench (org,practice,lesson) VALUES ('Mori Building (Nhật)','Diễn tập có cả cư dân + tenant; tòa nhà là điểm trú an toàn cho người mắc kẹt','Diễn tập KB-C1 cùng cư dân; phòng SHCĐ là điểm trú tập trung');
INSERT INTO bench (org,practice,lesson) VALUES ('Bài học Yagi 2024 (RRTT cấp 4, thiệt hại ~81,5 nghìn tỷ)','Vỡ kính mặt dựng hàng loạt; nước tràn khe cửa; ngập hầm sau bão; công trường phải hạ cẩu trước','KB-B3/B4/B5; quy tắc cẩu tháp cấp 8-12 hạ cần, ≥13 tháo cần; băng keo chữ X kính lớn');
INSERT INTO fire_steps (step,title,description,sla) VALUES (1,'BÁO ĐỘNG','Hô hoán + nhấn nút báo cháy gần nhất; ca trực xác nhận vị trí trên tủ báo cháy trung tâm.','≤1 phút');
INSERT INTO fire_steps (step,title,description,sla) VALUES (2,'GỌI 114','Gọi ngay Cảnh sát PCCC 114 (nêu rõ: địa chỉ, tầng, loại cháy — đặc biệt nếu là xe điện/tầng hầm); song song báo BCH.','≤2 phút');
INSERT INTO fire_steps (step,title,description,sla) VALUES (3,'CỨU NGƯỜI','Ưu tiên tuyệt đối: hướng dẫn thoát nạn theo thang bộ, khăn ướt che mũi; cứu người mắc kẹt; KHÔNG dùng thang máy.','Liên tục');
INSERT INTO fire_steps (step,title,description,sla) VALUES (4,'CẮT ĐIỆN','Cắt điện khu vực cháy (aptomat tầng/khu); thang máy đưa về tầng 1; giữ nguồn bơm chữa cháy.','≤3 phút');
INSERT INTO fire_steps (step,title,description,sla) VALUES (5,'CHỮA CHÁY','Đội PCCC cơ sở dùng bình + họng nước khống chế đám cháy trong khả năng; đón và bàn giao cho lực lượng 114 (sơ đồ, chìa khóa kỹ thuật).','≤4 phút tiếp cận');
