INSERT INTO qd03_principles (text) VALUES ('Phòng ngừa chủ động, từ sớm – từ xa; phương châm BỐN TẠI CHỖ: chỉ huy, lực lượng, phương tiện – vật tư, hậu cần tại chỗ.');
INSERT INTO qd03_principles (text) VALUES ('Ưu tiên tuyệt đối an toàn TÍNH MẠNG, sau đó an toàn điện, công trình, dữ liệu, tài sản — không đánh đổi an toàn con người để cứu tài sản.');
INSERT INTO qd03_principles (text) VALUES ('Chỉ huy tập trung, thông tin MỘT đầu mối; người nhận nhiệm vụ phải chấp hành lệnh và xác nhận kết quả bằng sổ/tin nhắn/ảnh/hệ thống điện tử.');
INSERT INTO qd03_principles (text) VALUES ('KHÔNG cứu nạn vượt quá năng lực – phương tiện – chuyên môn; người mắc kẹt, dòng chảy mạnh, sạt lở, điện nguy hiểm → báo cơ quan chuyên trách (112/114/115).');
INSERT INTO qd03_principles (text) VALUES ('Mọi vật tư, thiết bị, hàng cứu trợ: minh bạch, đúng mục đích, đúng đối tượng, có hồ sơ, kiểm tra sau sử dụng.');
INSERT INTO qd03_principles (text) VALUES ('Phương án từng cơ sở phải CỤ THỂ HƠN Quy định này — theo hiện trạng, quy mô, số người, hệ kỹ thuật, mức rủi ro.');
INSERT INTO qd03_forbidden (text) VALUES ('Không chấp hành lệnh dừng thi công, sơ tán, cô lập điện, đóng khu vực nguy hiểm hoặc điều động khẩn cấp.');
INSERT INTO qd03_forbidden (text) VALUES ('Tự ý vào khu vực ngập, hố sâu, mái, giàn giáo, cẩu tháp, vận thăng, phòng điện, nơi gió mạnh khi chưa xác nhận an toàn.');
INSERT INTO qd03_forbidden (text) VALUES ('Tự ý vận hành, tháo sửa máy bơm, máy phát, tủ điện, thiết bị cứu hộ/trọng yếu khi chưa được phân công.');
INSERT INTO qd03_forbidden (text) VALUES ('Dùng vật tư, thiết bị, hàng cứu trợ cho mục đích cá nhân; cho mượn, điều chuyển, thanh lý, tháo nhãn, sửa số liệu, ký bàn giao khống.');
INSERT INTO qd03_forbidden (text) VALUES ('Che giấu sự cố, chậm báo cáo, thông tin sai lệch; phát ngôn/đăng tải hình ảnh nhạy cảm khi chưa được phép.');
INSERT INTO qd03_forbidden (text) VALUES ('Phân phối cứu trợ không danh sách, không xác nhận, phân biệt đối xử, trục lợi, làm thất thoát nguồn lực.');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-01','Sổ danh mục & nhập – xuất – tồn kho','Thủ kho · cập nhật liên tục');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-02','Phiếu nhập kho / nghiệm thu (chạy thử thiết bị điện)','Kho + HCNS + Kỹ thuật (+ Tài chính khi cần)');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-03','Phiếu xuất dùng / điều chuyển / thu hồi','Người giao – nhận – thủ kho – phê duyệt');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-04','Sổ xuất KHẨN CẤP','Hoàn thiện phiếu đầy đủ ≤24h');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-05','Sổ bàn giao ca thiết bị & chìa khóa','Thử nhanh + ký 2 ca, ca trưởng xác nhận');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-06','Phiếu kiểm tra, chạy thử, bảo dưỡng','HCNS + Kỹ thuật/IT + BQL/Thủ kho');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-07','Biên bản sự cố / mất mát / hư hỏng','Lập ≤2h khi mất/hỏng thiết bị trọng yếu');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-08','Checklist chuẩn bị trước bão (10 hạng mục)','Trước T-24h, kèm ảnh xác nhận lần cuối');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-09','Báo cáo nhanh sự cố / bão lụt (8 mục)','≤4 giờ sau sự cố');
INSERT INTO qd03_forms (code,name,owner) VALUES ('BM-PCLB-10','Biên bản kiểm tra sau bão & CHO PHÉP HOẠT ĐỘNG LẠI','Kỹ thuật/ATLĐ + BQL/CHT + Giám đốc phê duyệt');
